package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetSkipHeaderRecord_DefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_TrueViaWithSkipHeaderRecord() {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(true);
        assertTrue(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_FalseViaWithSkipHeaderRecord() {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(false);
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_ReflectionAccess() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        Field field = CSVFormat.class.getDeclaredField("skipHeaderRecord");
        field.setAccessible(true);
        field.setBoolean(format, true);

        boolean result = (boolean) CSVFormat.class.getMethod("getSkipHeaderRecord").invoke(format);
        assertTrue(result);

        field.setBoolean(format, false);
        result = (boolean) CSVFormat.class.getMethod("getSkipHeaderRecord").invoke(format);
        assertFalse(result);
    }
}
